import React, { useEffect, useState } from 'react';
import './empresasPanel.css';

const EmpresasPanel = () => {
  const [empresas, setEmpresas] = useState([]);
  const [imagenLateral, setImagenLateral] = useState('');
  const [empresaSeleccionada, setEmpresaSeleccionada] = useState(null);

  // Datos estáticos simulados
  useEffect(() => {
    const empresasFake = [
      {
        nombre: 'HIDROPONIA',
        descripcion: 'Empresa de ejemplo para pruebas',
        imagen: 'https://via.placeholder.com/300x150?text=Hidroponia',
        infoAdicional: 'Servicios de desarrollo web, consultoría y más.',
        rubro: 'Agrotech',
        slogan: 'Cultivando el futuro'
      },
      {
        nombre: 'Otra Empresa',
        descripcion: 'Otra empresa de prueba',
        imagen: 'https://via.placeholder.com/300x150?text=Empresa',
        infoAdicional: 'Soluciones tecnológicas para la industria alimentaria.',
        rubro: 'Alimentaria',
        slogan: 'Creciendo con sabor'
      }
    ];
    setEmpresas(empresasFake);
    setImagenLateral('https://via.placeholder.com/300x300?text=Imagen+Lateral');
  }, []);

  const abrirModal = (empresa) => {
    setEmpresaSeleccionada(empresa);
  };

  const cerrarModal = () => {
    setEmpresaSeleccionada(null);
  };

  return (
    <div>
      {/* Barra superior */}
      <div className="barra-superior">
        <div className="barra-izquierda">
          ANTIGÜEDAD <span>↕</span>
        </div>
        <div className="barra-centro">
          <input type="text" placeholder="Buscar empresa..." />
        </div>
        <div className="barra-derecha">
          <button><img src="/iconos/icon1.png" alt="Icono 1" /></button>
          <button><img src="/iconos/icon2.png" alt="Icono 2" /></button>
          <button><img src="/iconos/icon3.png" alt="Icono 3" /></button>
          <button><img src="/iconos/icon4.png" alt="Icono 4" /></button>
        </div>
      </div>

      {/* Contenedor principal */}
      <div className="empresas-panel-container">
        {/* Parte izquierda: imagen lateral */}
        <div className="imagen-lateral">
          {imagenLateral && <img src={imagenLateral} alt="Imagen lateral" />}
        </div>

        {/* Parte derecha: lista de empresas */}
        <div className="empresas-panel">
          <h2 className="empresas-titulo">Empresas</h2>
          <div className="empresas-grid">
            {empresas.map((empresa, index) => (
              <div
                key={index}
                className="empresa-card"
                onClick={() => abrirModal(empresa)}
              >
                <div className="empresa-imagen-contenedor">
                  <img src={empresa.imagen} alt={empresa.nombre} />
                  <div className="empresa-overlay-text">
                    <div className="empresa-nombre">{empresa.nombre}</div>
                    <div className="empresa-rubro">{empresa.rubro}</div>
                    <div className="empresa-slogan">{empresa.slogan}</div>
                  </div>
                </div>
                <div className="empresa-info-box"></div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Modal */}
      {empresaSeleccionada && (
        <div className="modal-overlay" onClick={cerrarModal}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={cerrarModal}>X</button>
            <img src={empresaSeleccionada.imagen} alt={empresaSeleccionada.nombre} className="modal-img" />
            <h2>{empresaSeleccionada.nombre}</h2>
            <p><strong>Descripción:</strong> {empresaSeleccionada.descripcion}</p>
            <p><strong>Información adicional:</strong> {empresaSeleccionada.infoAdicional}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmpresasPanel;
